@@ -0,0 +1,50 @@
+package persistence
+
+import (
+	"testing"
+
+	"github.com/navidrome/navidrome/conf"
+	"github.com/navidrome/navidrome/consts"
+	"github.com/navidrome/navidrome/model"
+)
+
+func TestPostScan_NormalizedMode_ZeroSongCount(t *testing.T) {
+	conf.Server.AlbumPlayCountMode = consts.AlbumPlayCountModeNormalized
+	dba := dbAlbum{Album: &model.Album{ID: "1", Name: "name", SongCount: 0, Annotations: model.Annotations{PlayCount: 50}}, Discs: "{}"}
+	err := dba.PostScan()
+	if err != nil {
+		t.Fatalf("PostScan failed: %v", err)
+	}
+	if dba.Album.PlayCount != 0 {
+		t.Errorf("Expected PlayCount=0 when SongCount=0, got %d", dba.Album.PlayCount)
+	}
+}
+
+func TestPostScan_NormalizedMode_FloorRounding(t *testing.T) {
+	conf.Server.AlbumPlayCountMode = consts.AlbumPlayCountModeNormalized
+	// 19/4 = 4.75, floor = 4, round would give 5
+	dba := dbAlbum{Album: &model.Album{ID: "1", Name: "name", SongCount: 4, Annotations: model.Annotations{PlayCount: 19}}, Discs: "{}"}
+	err := dba.PostScan()
+	if err != nil {
+		t.Fatalf("PostScan failed: %v", err)
+	}
+	// floor(4.75) = 4, round(4.75) = 5
+	if dba.Album.PlayCount != 4 {
+		t.Errorf("Expected PlayCount=4 (floor of 4.75), got %d", dba.Album.PlayCount)
+	}
+}
+
+func TestPostScan_NormalizedMode_CompilationAlbum(t *testing.T) {
+	conf.Server.AlbumPlayCountMode = consts.AlbumPlayCountModeNormalized
+	// Compilation album with PlayCount=20, SongCount=5
+	// Even though Compilation=true, normalization MUST apply: 20/5 = 4
+	dba := dbAlbum{Album: &model.Album{ID: "1", Name: "Greatest Hits", SongCount: 5, Compilation: true, Annotations: model.Annotations{PlayCount: 20}}, Discs: "{}"}
+	err := dba.PostScan()
+	if err != nil {
+		t.Fatalf("PostScan failed: %v", err)
+	}
+	// Normalization must apply to compilations: 20/5 = 4
+	if dba.Album.PlayCount != 4 {
+		t.Errorf("Expected PlayCount=4 for compilation album (20/5), got %d", dba.Album.PlayCount)
+	}
+}
